local Cache = {}

RespawnHelper = {}

RespawnCountdownType = {
    Cancel = 0,
    Respawn = 1
}

function RespawnHelper.sendRespawnCountdown(player, seconds)
    RespawnHelper.addRespawnCountdown(player, seconds)
    HostApi.sendRespawnCountDown(player.rakssid, seconds)
end

function RespawnHelper.addRespawnCountdown(player, seconds, type)
    type = type or RespawnCountdownType.Respawn
    if type == RespawnCountdownType.Cancel then
        Cache[player.userId] = nil
        return
    end
    if type == RespawnCountdownType.Respawn then
        Cache[player.userId] = seconds * 1000
    end
end

function RespawnHelper.tryPlayerRespawn(delay)
    local respawn = {}
    for userId, cache in pairs(Cache) do
        Cache[userId] = cache - delay
        if cache <= 0 then
            table.insert(respawn, userId)
        end
    end
    for _, userId in pairs(respawn) do
        Cache[userId] = nil
        local player = PlayerManager:getPlayerByUserId(userId)
        if player and player.entityPlayerMP and player.entityPlayerMP.isDead and player.clientPeer then
            player.clientPeer:rebirth()
        end
    end
end